class Solution {
public:
    bool isRationalEqual(string s, string t) {
        int n = s.length();
        int m = t.length();

        if (n != m) return false;

        int integerPart[n];
        int repeatingPart[n];
        int nonRepeatingPart[n];

        for (int i = 0; i < n; i++) {
            integerPart[i] = stoi(s.substr(i, 1));
            repeatingPart[i] = stoi(t.substr(i, 1));
            nonRepeatingPart[i] = stoi(t.substr(i, 1));
        }

        for (int i = 0; i < n; i++) {
            if (integerPart[i] != t[i] || repeatingPart[i] != t[i+1] || nonRepeatingPart[i] != t[i+2]) {
                return false;
            }
        }

        return true;
    }
};
```

